"""
MKT Original Commentary — Mark chapters 5–6
Run: python3 scripts/zc-original-mark-5-6.py

Source data used:
- data/interlinear/mark.json
- data/translation/draft/mediating/mark.json
- data/commentary/mkt-original/mark.json (existing entries skipped by merge_comm)

Key decisions in this range:
- v5:1 Gerasenon: three-way textual variant (Gerasenes/Gadarenes/Gergesenes);
  UBS5 reads Gerasenon; Gadara and Gerasa are both ~30 miles from the lake
- v5:19 ho kyrios: "the Lord" = God (divine mercy framing) vs. Jesus — the narrator
  then substitutes "Jesus" in v.20, creating a Lord = Jesus equation
- v5:30 dynamin exelelythuian: power having gone out — unmediated, not requested
- v6:3 ho tekton: the craftsman/carpenter — Matthew reads "son of the carpenter";
  Mark names Jesus himself the craftsman, unique among the Gospels
- v6:5 ouk edynato: "could not" — strong limitation; many soften to "would not"
- v6:48 parelthein autous: "pass by them" — theophanic language (Ex 33-34; 1 Kgs 19)
- v6:50 ego eimi: "I AM" — the divine name in the storm theophany
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MARK = {
  "5": {
    "1": '<p><strong>Kai Elthan eis to peran tes thalasses eis ten chOran tOn GerasenOn</strong> — and they came to the other side of the sea, into the region of the Gerasenes — the textual variant is three-way: Gerasenes (<em>GerasenOn</em>), Gadarenes (<em>GadarEnOn</em>), or Gergesenes (<em>GergesEnOn</em>). UBS5/NA28 reads Gerasenes; Matthew 8:28 reads Gadarenes; Origen proposed Gergesenes to avoid the geographical problem (Gerasa is roughly 35 miles southeast of the lake; Gadara is about 6 miles southeast). The difficulty is that neither city is on the lakeshore where the pigs ran into the sea. The geographical imprecision may reflect the use of major city names to designate regions rather than precise locations. The key point is that this is Gentile territory east of the Jordan: the Decapolis.</p>',
    "2": '<p><strong>Kai exelthontos autou ek tou ploiou euthys hupEntEsen autO ek tOn mnEmeion anthrOpos en pneumati akathartO</strong> — and as he was getting out of the boat, immediately there met him from the tombs a man in an unclean spirit — <em>euthys</em> again; the encounter is immediate, before Jesus has even left the beach. <em>HupantaO</em> (to go/come to meet, encounter) can be hostile (as in military engagement) or simply a meeting on the road. The man comes from the tombs (<em>ek tOn mnEmeion</em>): he lives among the dead, the extreme of social and ritual exclusion. The description that follows (vv.3-5) is the most detailed portrait of severe demonization in the Gospels.</p>',
    "3": '<p><strong>Hos ten katoikEsin eichen en tois mnEmasin</strong> — who had his dwelling in the tombs — <em>katoikEsis</em> (dwelling, habitation — from <em>katoeO</em>, to settle and dwell in) is the word for permanent residence: the tombs are not a temporary shelter but his home. The tombs (rock-cut burial chambers in the hillside) were outside the inhabited area, ritually impure, and excluded from normal community life. <strong>Kai oute halysei ouketi oudeis edynato auton dEsai</strong> — and no one could any longer bind him even with a chain — the emphatic negative triple (<em>oute ... ouketi ... oudeis</em>) stresses the total failure of human restraint: every attempt at social control has failed.</p>',
    "4": '<p><strong>Dioti pollakis pedais kai halysesin dedesthai kai diespasthai hyp\' autou tas halyseias kai tas pedas syntetriphthai</strong> — because he had often been bound with shackles and chains, and the chains had been torn apart by him and the shackles broken in pieces — the iterative <em>pollakis</em> (often, repeatedly) and the perfect passive <em>dedesthai</em> (had been bound — the accomplished state of binding that the aorists of tearing undo) create the picture of repeated failed restraint. The verb <em>diespasthai</em> (torn apart, pulled asunder) is a strong word for violent destruction. <strong>Kai oudeis ischyen auton damasai</strong> — and no one had strength to subdue him — <em>damazO</em> (to tame, subdue — used for wild animals) identifies the condition: he has become ungovernable, beyond human taming.</p>',
    "5": '<p><strong>Kai dia pantos nyktos kai hEmEras en tois mnEmasin kai en tois oresin En krazon kai katakopton heauton lithois</strong> — and night and day among the tombs and in the hills he was crying out and cutting himself with stones — the perpetual restlessness (<em>dia pantos nyktos kai hEmEras</em> = throughout night and day, without ceasing) and the self-harm (<em>katakopton heauton lithois</em> = cutting himself with stones — <em>katatkopto</em> from <em>kata</em> + <em>kopto</em>, to beat/cut down) is the picture of a human being at the extreme limit of disintegration. No sleep, no community, constant self-destruction. The scene establishes that what Jesus is about to accomplish is the rescue of a person from the most extreme bondage the Gospels depict.</p>',
    "6": '<p><strong>IdOn de ton IEsoun apo makrothen edramen kai prosekynEsen autO</strong> — and seeing Jesus from a distance, he ran and prostrated himself before him — two verbs in sequence: <em>edramen</em> (he ran — the immediate, urgent movement toward Jesus across the distance) and <em>prosekynEsen</em> (he prostrated, worshiped/did obeisance — the same verb used for genuine worship). The unclean-spirit-controlled man runs toward Jesus and prostrates before him — the same involuntary submission as 3:11 (the spirits fell before him). The demon\'s movement is compelled rather than chosen; the human being within is being drawn toward the only source of liberation.</p>',
    "8": '<p><strong>Elegen gar autO, Exelthe to pneuma to akatharton ek tou anthrOpou</strong> — for he had been saying to him: "come out of the man, you impure spirit!" — the <em>gar</em> (for) makes v.8 explanatory: the cry of v.7 ("in God\'s name don\'t torture me!") was a response to Jesus\'s prior command. The exorcism command (<em>exelthe ek tou anthrOpou</em> = come out of the man) had already been issued before the name-asking. This means the demon\'s pleading in vv.7,10 is resistance to a command already given — the unclean spirit is attempting to negotiate or delay, not simply to identify itself. The sequence: command given → demonic resistance → name-inquiry → final expulsion.</p>',
    "9": '<p><strong>Kai epErOta auton, Ti onoma soi? kai legei autO, Legiōn onoma moi, hoti polloi esmen</strong> — and he asked him: "what is your name?" and he said to him: "Legion is my name, for we are many" — <em>LegEOn</em> (Legion) is a Latin loanword in Greek: the standard Roman military unit of approximately 5,000 infantry plus cavalry and support (varying by period, 4,000-6,000). The self-identification with a Roman military unit is the deepest irony of the pericope: the occupying power\'s organizational structure has been adopted by the demonic possession as its name. The answer "we are many" (<em>polloi esmen</em>) clarifies that the name describes multitude, not a single demon named Legion. Whether this is meant to indicate the actual number 5,000 or simply extreme multitude is debated.</p>',
    "10": '<p><strong>Kai parekAlei auton polla hina mE autous aposteilE exO tes chOras</strong> — and he begged him earnestly not to send them out of the area — the territorial instinct of the demonic: <em>exO tes chOras</em> (outside/beyond the region). This detail appears across demonology: the idea that spirits are bound to or prefer specific territories. Luke 8:31 specifies the request not to go into the <em>abyss</em>. The desperation of the pleading (<em>parekAlei</em> = was earnestly begging, the same verb used by Jairus in v.22) reveals the hierarchy of the encounter: the Legion that no human could subdue is reduced to begging before Jesus.</p>',
    "11": '<p><strong>En de ekei pros tO orei agelE choirOn megalE boskomenE</strong> — and there was there near the mountain a large herd of pigs grazing — the herd of pigs signals definitively that this is Gentile territory: Jewish communities did not raise pigs (Lev 11:7; Deut 14:8). The pigs grazing on the hillside near the tombs complete the scene\'s composite of Gentile uncleanness: Gentile territory, tombs (corpse-impurity), unclean animals. Into this landscape of multiple impurities Jesus arrives and acts.</p>',
    "12": '<p><strong>Kai parekalesan auton legontes, Pempon hEmas eis tous choirous, hina eis autous eiselthOmen</strong> — and they begged him saying: "send us into the pigs so that we may enter them" — the demons negotiate their own disposal: they request the pigs rather than exile from the region. The request is granted (v.13 <em>epetrepsen autois</em> = he gave them permission). The compliance with the demonic request has generated theological discussion: why does Jesus permit this? The narrative focus is entirely on the outcome (the man\'s liberation), not on theological justification for the pigs\' destruction.</p>',
    "13": '<p><strong>Kai exelthonta ta pneumata ta akatharta eisElthon eis tous choirous, kai hOrmEsen hE agelE kata tou krEmnou eis ten thalassan</strong> — and the unclean spirits came out and entered into the pigs, and the herd rushed down the steep bank into the sea — <em>hOrmEsen</em> (rushed, charged — of a stampede) is the vivid verb of the herd\'s headlong rush. <em>Kata tou krEmnou</em> (down the steep bank — <em>krEmnos</em> = a precipice, steep drop) creates the specific geography. The herd of about two thousand (<em>hOs dischilioi</em>) drowns in the sea. The scale of destruction is vast; Mark preserves the number without explanation or mitigation.</p>',
    "14": '<p><strong>Kai hoi boskontes autous ephygon kai apEngeilan eis ten polin kai eis tous agrous</strong> — and those herding them fled and reported it in the city and in the fields — the flight of the herdsmen is the immediate human response to the catastrophic loss and the inexplicable event. <em>Apanggellō</em> (to report, announce — the herald verb) carries the news to both the urban and rural populations. The news spreads in two directions: the town and the countryside receive the same report. The result in v.14b-17 will be the community\'s collective response to Jesus\'s arrival.</p>',
    "15": '<p><strong>Kai erchontai pros ton IEsoun kai theOrousin ton daimoniZomenon kathEmenon himatismenon kai sOphronounta, ton eschEkota ton legiOna</strong> — and they came to Jesus and saw the demonized man sitting, clothed and in his right mind, the one who had the legion — the three participial conditions of the healed man are the precise reversals of his former condition: sitting (not running and crying) / clothed (not naked — implied by the contrast, and explicit in Luke 8:27) / in his right mind (<em>sOphronounta</em> = being of sound mind, the same root as <em>sOphrosynE</em>, sound-mindedness/self-control, the virtue of ordered rational thought). <strong>Kai ephobEthEsan</strong> — and they were afraid — the community\'s response to healing is fear, as in 4:41.</p>',
    "16": '<p><strong>Kai diEgEsanto autois hoi idontes pOs egeneto tO daimoniZomenO kai peri tOn choirOn</strong> — and those who had seen it described to them how it had happened to the demon-possessed man and about the pigs — the eyewitness report (<em>hoi idontes</em> = those who had seen) covers both the healing and the pigs. The conjunction "and about the pigs" (<em>kai peri tOn choirOn</em>) puts the man and the herd in the same report — the community\'s economic concern (the pigs represent significant wealth destroyed) is as prominent as their theological concern. The double report sets up the community\'s response in v.17.</p>',
    "17": '<p><strong>Kai Erxanto parakalein auton apelthein apo tOn horiOn autOn</strong> — and they began to beg him to leave from their region — the community that saw a man freed from Legion begs Jesus to depart. The word <em>parakalein</em> (to beg, implore) used for the Legion\'s request (v.10,12) is now used by the human community: they plead with Jesus the way the demons pleaded. The economic loss (2,000 pigs) likely drives the expulsion request; the supernatural power that freed the man and destroyed the herd is unwanted in their territory.</p>',
    "18": '<p><strong>Kai embainontos autou eis to ploion parekAlei auton ho daimoniStheis hina met\' autou E</strong> — and as he was getting into the boat, the formerly demonized man begged him that he might be with him — <em>hina met\' autou E</em> (to be with him) echoes the founding purpose of the Twelve: <em>hina Osin met\' autou</em> (3:14, to be with him). The healed man asks for the same relationship that Jesus constituted in the apostolic appointment. This is the only person in Mark who begs to follow Jesus and is sent away. The contrast with the Twelve who were called but needed persuasion (and the two who left everything immediately) is notable.</p>',
    "19": '<p><strong>Kai ouk aphEken auton, alla legei autO, Hypage eis ton oikon sou pros tous sous kai apAggeilon autois hosa ho kyrios soi pepoiEken kai ElEEsen se</strong> — and he did not permit him, but said to him: "go to your house, to your own people, and report to them how much the Lord has done for you and how he had mercy on you" — the commission: <em>ho kyrios</em> (the Lord) refers to God in the phrasing but v.20 will replace it with "Jesus" (<em>hosa epoiEsen autO ho IEsous</em>), creating a Lord = Jesus equation by the narrator\'s substitution. The mission to the Decapolis is the first explicit Gentile mission in Mark: the healed man becomes the missionary to the 10 Hellenistic cities of the region.</p>',
    "20": '<p><strong>Kai apElthen kai Erxato kEryssein en te Dekapolei hosa epoiEsen autO ho IEsous kai pantes ethaumazon</strong> — and he went away and began to proclaim in the Decapolis how much Jesus had done for him, and all were amazed — <em>DekapolIs</em> (Ten Cities — the league of Hellenistic city-states east of the Jordan including Damascus, Gerasa, Philadelphia, Gadara, and others) is the mission field of the healed Gentile. His proclamation (<em>kEryssein</em> = to herald, the same word as the apostolic preaching commission of 3:14) in all ten cities is the widest reach any single individual\'s testimony has in Mark\'s narrative. The amazement (<em>ethaumazon</em>) is the standard response to unexpected divine intervention.</p>',
    "21": '<p><strong>Kai diaperasantos tou IEsou en tO ploiO palin eis to peran synEchthE ochlos polys ep\' auton</strong> — and Jesus having crossed back in the boat to the other side, a large crowd gathered to him — the return crossing from Gentile territory back to Jewish Galilee resumes the central narrative thread. The crowd immediately gathers (<em>synEchthE</em> = gathered together), consistent with the fame established in 1:28,45; 2:1-2; 3:7-8. The lakeside setting continues as the primary public space of the Galilean ministry.</p>',
    "22": '<p><strong>Kai erchetai heis tOn archisyagOgOn, onomati Iaeiros</strong> — and one of the synagogue rulers came, named Jairus — the naming of a named individual is notable: Mark names relatively few of the people Jesus encounters. <em>ArchisyagOgos</em> (ruler of the synagogue, president of the synagogue community — responsible for maintaining the building, organizing worship, selecting readers and preachers) is a position of social honor and religious authority. This man of the establishment comes to Jesus and falls at his feet (<em>piptei pros tous podas autou</em>), the same posture of desperate supplication as the demonized man of 5:6.</p>',
    "23": '<p><strong>Kai parekAlei auton polla legOn hoti to thygatrion mou eschatOs echei</strong> — and he begged him earnestly, saying: "my little daughter is at the last gasp" — <em>eschatOs echei</em> (is at the extreme, is at the last gasp — from <em>eschatos</em>, last, extreme) is a medical idiom for terminal condition. <em>Thygatrion</em> (little daughter — diminutive of <em>thygater</em>) is the affectionate parental form. <strong>Hina elthOn epithEs auts tas cheiras hina sOthE kai zEsE</strong> — in order that coming you might lay your hands on her so that she might be saved and live — the double <em>hina</em> purpose clause: hands-on (the physical healing gesture) → saving and living. <em>SōthE kai zEsE</em> (be saved and live) — both verbs carry their theological weight beyond mere medical healing.</p>',
    "24": '<p><strong>Kai apElthen met\' autou kai EkolouthEi autO ochlos polys kai synEthliban auton</strong> — and he went with him and a large crowd was following him and was pressing/crushing against him — <em>synEthliban</em> (from <em>synthlibO</em> = to press together, crush from all sides — the same root as <em>thlipsis</em>, tribulation/affliction) describes the crowd\'s physical pressure on Jesus. The crowd that is simultaneously following Jesus to Jairus\'s house becomes the medium through which the hemorrhaging woman will reach him: hidden within the pressing crowd, she can approach without announcement.</p>',
    "25": '<p><strong>Kai gynE tis ousa en rhusei haimatos dOdeka etE</strong> — and a certain woman who was in a flow of blood for twelve years — <em>rhusis haimatos</em> (a flow/discharge of blood) refers to chronic abnormal uterine bleeding. Leviticus 15:25-30 classifies such a condition as <em>tum\'a</em> (ritual impurity): the woman is continually in the state that renders her unable to participate in community worship and transmits impurity by touch. Twelve years of this condition means twelve years of social-ritual exclusion that mirrors (and the narrative will pair with) Jairus\'s twelve-year-old daughter. The age of the daughter and the duration of the woman\'s illness are the same number — the interlocking stories share the twelve.</p>',
    "26": '<p><strong>Kai polla pathousa hypo pollOn iatrOn kai dapanEsasa ta par\' heautEs panta kai mEden OphElEtheisa alla mallon eis to cheiron elthousa</strong> — having suffered much under many physicians and having spent everything she had and not having been helped at all but rather having come to the worse — the triple compound of failed medicine: much suffering (<em>polla pathousa</em>), total impoverishment (<em>dapanEsasa ta par\' heautEs panta</em> = having spent all that was beside herself = all her possessions), and deterioration despite treatment (<em>eis to cheiron elthousa</em> = having gone to the worse). Mark\'s portrait of the medical system\'s failure is unsparing: both her funds and her condition have been exhausted by human medicine. What twelve years of physicians could not achieve will take a moment of touch.</p>',
    "27": '<p><strong>AkOusasa peri tou IEsou, elthousa en tO ochlO opisthEn hEpsato tou himatiou autou</strong> — having heard about Jesus, coming in the crowd from behind she touched his garment — the sequence: hearing about Jesus (<em>akOusasa</em>) → coming in the crowd from behind (hidden approach, maintaining anonymity) → touching the garment (<em>hEpsato tou himatiou</em>). The touch is indirect and minimal: not his body but his garment (<em>himation</em> = outer robe/cloak). The approach from behind avoids the confrontation she dreads: she intends to receive healing without announcement, reversing the flow of impurity (she should make those she touches unclean; but she expects that touching him will make her clean).</p>',
    "28": '<p><strong>Elegen gar hoti Ean hapsOmai kan tOn himatiOn autou sOthEsomai</strong> — for she was saying: "if I touch even his garments I will be saved/healed" — <em>sOthEsomai</em> (I will be saved — the same <em>sOzO</em> verb used for Jairus\'s daughter in v.23 and for the healing pronouncement in v.34). The woman\'s inner speech (<em>elegen</em> = she was saying, internal monologue) reveals the logic: even the edge of his garment possesses healing power. This is not magic-thinking but the recognition that the divine power resident in Jesus radiates outward. The faith expressed in the attempt is what Jesus will identify as the operative principle (v.34).</p>',
    "29": '<p><strong>Kai euthys exErAnthE hE pEgE tou haimatos autEs</strong> — and immediately the source of her blood dried up — <em>euthys</em>; the healing is instant. <em>HE pEgE tou haimatos</em> (the source/spring of the blood — <em>pEgE</em> = spring, source, fountain) is a vivid anatomical image: the flow\'s origin is dried up (<em>exEranthe</em> = the same root <em>xErainO</em> as the withered hand of 3:1). <strong>Kai egnO tO sOmati hoti iatai apo tes mastigos</strong> — and she knew in her body that she had been healed from the affliction — <em>egnO tO sOmati</em> (knew in/by her body — the body as the organ of physical self-knowledge) is the immediate proprioceptive awareness. <em>Mastix</em> (whip, affliction — used in 3:10 for the crowd\'s diseases) is the word for her condition: a scourge that has been removed.</p>',
    "30": '<p><strong>Kai euthys ho IEsous epignous en heautO tEn ex autou dynamin exelElythuian</strong> — and immediately Jesus, having known in himself that power had gone out from him — <em>epiginOskO en heautO</strong> (having known in himself — immediate internal perception, the same kind of spiritual knowledge as 2:8) perceives the <em>dynamin exelElythuian</em> (power having gone out — perfect active participle of <em>exerchomai</em>, the power has departed and remains absent). The power goes out without Jesus\'s conscious direction: the healing is initiated by the woman\'s faith and Jesus\'s latent healing-power, not by an explicit command. This is unique in the healing narratives. <strong>Epistrapheis en tO ochlO elegen, Tis mou hEpsato tOn himatiOn?</strong> — turning in the crowd he said: "who touched my garments?" — the question is genuine, not rhetorical.</p>',
    "31": '<p><strong>Kai elegon autO hoi mathEtai autou, BlepEis ton ochlon synthlibonta se kai legeis, Tis mou hEpsato?</strong> — and his disciples said to him: "you see the crowd pressing in on you and you say \'who touched me?\'" — the disciples\' incredulity is reasonable: in a crushing crowd, the question seems absurd. Their response reveals they have not grasped the distinction between the crowd\'s incidental jostling (<em>synthlibO</em>) and the intentional, faith-driven touch. Jesus distinguishes between contact and touch — the whole crowd is in contact but only one person has touched in the theologically significant sense.</p>',
    "32": '<p><strong>Kai periblepeto idein ten touto poiEsasan</strong> — and he was looking around to see the one who had done this — <em>periblepeto</em> (was looking around — imperfect, sustained scanning action) is the characteristic Markan gaze of Jesus (3:5,34; 9:8; 10:23). He scans the crowd for the one person in it whose contact was different in kind. The woman knows she is the subject of the search (v.33: <em>egnOsa hoti ho gegonen en autE</em> = having known what had happened to her).</p>',
    "33": '<p><strong>HE de gynE phobEtheisa kai tremousa, eidyia ho gegonen autE, Elthen kai prosepesen autO kai eipen autO pasan ten alEtheian</strong> — but the woman, fearing and trembling, knowing what had happened to her, came and fell before him and told him the whole truth — <em>phobEtheisa kai tremousa</em> (fearing and trembling — the two fear-words combined) is the physical response to the exposure of what she has done: touched a rabbi while ritually impure, without permission. <em>Eipen autO pasan ten alEtheian</em> (told him the whole truth) — the public confession before the crowd reverses the anonymous concealment of the approach. The healing sought in secret is now proclaimed openly.</p>',
    "34": '<p><strong>Ho de eipen autE, Thygater, hE pistis sou sesOken se</strong> — and he said to her: "Daughter, your faith has saved you" — the same <em>teknon/thygater</em> (child/daughter) address of affection as in 2:5, now directed at a woman rather than a man. <em>HE pistis sou sesOken se</em> (your faith has saved you — perfect tense: has saved and the salvation remains) is the Christological statement about the operative cause: not the garment, not the residual power, but her faith. The faith was what connected the woman to the healing power; the power was already present. <strong>Hypage eis eirEnEn</strong> — go into peace — <em>eis eirEnEn</em> (into peace — the directional preposition, not merely "in peace") sends her forward into a state of wholeness. <em>Kai isthi hygiEs apo tEs mastigos sou</em> — and be well from your affliction — the present imperative <em>isthi</em> (be, continue to be) is the ongoing state of health now confirmed.</p>',
    "35": '<p><strong>Eti autou lalountos erchontai apo tou archisyagOgou legontes hoti hE thygatEr sou apethanen, ti eti skylleis ton didaskalon?</strong> — while he was still speaking, they came from the synagogue ruler\'s house saying: "your daughter has died; why do you still trouble the teacher?" — the interruption arrives mid-speech: <em>eti autou lalountos</em> (while he was still speaking). The messengers\' message contains both a death-announcement (<em>apethanen</em> = she has died) and a dismissal of Jesus\'s relevance (<em>ti eti skylleis ton didaskalon?</em> = why do you still trouble/disturb the teacher?). <em>Skylleis</em> (to trouble, harass, flay — a strong word) implies that further involvement of Jesus is now pointless, even burdensome. The death converts the request from healing to impossible resurrection.</p>',
    "36": '<p><strong>Ho de IEsous parakoussas ton logon laloumenon legei tO archisyagOgO, ME phobou, monon pisteue</strong> — but Jesus, having overheard/ignored the word being spoken, said to the synagogue ruler: "do not fear, only believe" — <em>parakoussas</em> (having overheard — the verb can mean to hear and disregard or to hear accidentally). The ambiguity is productive: Jesus may have heard the messenger\'s report and chosen to disregard the implied finality of death; or he overhears it while addressing Jairus. Either way, he responds not to the death-news but with the command: <em>mE phobou, monon pisteue</em> (stop fearing, only believe) — the same pattern as the stilling of the storm (4:40: <em>ti deiloi este, oupO echete pistin?</em>). Faith is the appropriate response to what Jesus is about to do; fear is the inappropriate one.</p>',
    "37": '<p><strong>Kai ouk aphEken oudena met\' autou synakolouthEsai ei mE ton Petron kai Iakōbon kai IOannEn ton adelphon Iakōbou</strong> — and he did not allow anyone to follow with him except Peter and James and John the brother of James — the inner circle of three (<em>Petros kai Iakōbos kai IOannEs</em>) who are the only witnesses to the Transfiguration (9:2) and the Gethsemane prayer (14:33). Their designation as witnesses to the resurrection of Jairus\'s daughter is the first instance of the three-apostle inner circle. The exclusion of the wider crowd is both practical (crowd management) and theological (the miracle requires the selective witness of those whose testimony will be shaped by repeated extraordinary experiences).</p>',
    "38": '<p><strong>Kai erchetai eis ton oikon tou archisyagOgou kai theOrei thorybion pollEn kai klaiOntais kai alalAZontas</strong> — and he came to the house of the synagogue ruler and observed a great commotion, and people weeping and wailing loudly — <em>thorybos</em> (commotion, tumult) is the noise of a household in mourning. <em>KlaionteS</em> (weeping — the ordinary grief-word) and <em>alalAZontas</em> (wailing loudly — from <em>alalagmos</em>, the battle cry or ritual lamentation shout) describe the professional mourners hired for the occasion. Jewish mourning practice included hired mourners, flutes, and loud lamentation that would have begun immediately upon death. The house is already in full mourning mode.</p>',
    "39": '<p><strong>Kai eiselthOn legei autois, Ti thorybEIsthe kai klaiEte? to paidion ouk apethanen alla katheudei</strong> — and entering he said to them: "why do you make commotion and weep? the child has not died but is sleeping" — <em>to paidion ouk apethanen alla katheudei</em> (the child has not died but sleeps) is the Christological statement whose ambiguity is intentional: is Jesus correcting their diagnosis (she appears dead but is only in a coma-like sleep)? Or is he using "sleep" as a euphemism for death, indicating that from his perspective the boundary between sleep and death is crossable? The mourners\' laughter (<em>kategelOn autou</em> = they ridiculed him) shows they took it as a denial of an obvious fact — she was dead and they knew it. The text supports the latter interpretation: the command <em>egeirai</em> (arise!) in v.41 treats her as needing resurrection, not awakening.</p>',
    "40": '<p><strong>Kai kategelOn autou</strong> — and they ridiculed/laughed at him — <em>katagelAO</em> (to laugh down at, deride, mock) is the contemptuous response of those who know what death is and find Jesus\'s statement absurd. Their laughter is the Christological irony: those who mock will witness the resurrection. <strong>HO de ekbalOn pantas</strong> — but having cast out all — <em>ekbalOn</em> (having cast out — the exorcism verb!) is used for the dismissal of the crowd: the same word used for casting out demons is used for Jesus removing the mockers from the resurrection scene. The removal is forceful and purposeful; the resurrection happens before a small circle of witnesses, not an audience of skeptics.</p>',
    "42": '<p><strong>Kai euthys anestE to korasion kai periepatei En gar etOn dOdeka</strong> — and immediately the girl stood up and began to walk, for she was twelve years old — <em>euthys anestE</em> (immediately she stood up — the resurrection verb <em>anistEmi</em> in the aorist) and <em>periepatei</em> (began to walk — imperfect, sustained action). The age specification (<em>En gar etOn dOdeka</em> = she was twelve years old) closes the narrative-numerical bracket: the hemorrhaging woman\'s 12-year affliction / the girl\'s 12 years of life. Both the twelve years are healed in the same encounter. <strong>Kai exestEsan ekstasei megalE</strong> — and they were amazed with a great amazement — the cognate construction (<em>existEmi + ekstasis</em>) for maximal astonishment.</p>',
    "43": '<p><strong>Kai diesteilato autois polla hina mEdeis gnO touto</strong> — and he gave them many strict orders that no one should know this — the most impossible Messianic Secret command in Mark: the girl who was dead is now alive and walking, and Jesus commands that no one know. The command is clearly unrealistic given the circumstances (the household in mourning, the neighbors, the professional mourners just sent out). The Messianic Secret is a theological principle rather than a sociological strategy: it marks the resurrection as not yet the time for public Christological disclosure. <strong>Kai eipen dothEnai autE phagein</strong> — and he said to give her something to eat — the physical need following restoration to life is the most tender and human note: she is alive and needs food. The command grounds the miraculous in the practical.</p>'
  },
  "6": {
    "1": '<p><strong>Kai exElthen ekeithen kai erchetai eis ten patrida autou</strong> — and he left there and came to his hometown — <em>patris</em> (hometown, fatherland — from <em>patEr</em>, father) is the place of one\'s paternal origin: the village where one\'s family is known. <strong>Kai akolouthousin autO hoi mathEtai autou</strong> — and his disciples followed him — the specification "his disciples followed him" is transitional: the Nazareth episode is the end of the first section of Galilean ministry and the beginning of the second. The failure at Nazareth (vv.2-6) motivates the expansion of the mission through the Twelve (vv.7-13).</p>',
    "2": '<p><strong>Kai genomEnou sabbatou Erxato didaskein en tE synagOgE</strong> — and when the Sabbath came he began to teach in the synagogue — the pattern of Sabbath synagogue teaching (1:21) is repeated in his hometown. The congregation\'s initial response is amazement (<em>exeplessonto</em> = they were astonished, 1:22) but the amazement curdles into offense. <strong>Pothen toutO tauta? kai tis hE sophia hE dotheisa autO?</strong> — "where did this man get these things? and what is this wisdom that has been given to him?" — the questions are authentic: the source (<em>pothen</em> = from where) of his teaching and the origin (<em>dotheisa</em> = given — the divine passive) of his wisdom. The questions are not hostile in themselves; the problem is that the answers cannot come from within their frame of reference.</p>',
    "3": '<p><strong>Ouch houtos estin ho tektOn, ho hyios tEs Marias</strong> — "is this not the craftsman, the son of Mary?" — <em>tekton</em> (craftsman, builder — used for workers in wood, stone, or metal; not exclusively "carpenter" in the modern narrow sense) is Jesus\'s own vocational identity in Mark, not merely his father\'s. Matthew 13:55 reads "the son of the craftsman" (<em>ho tou tektonos hyios</em>), identifying Joseph. Mark uniquely names Jesus himself as the craftsman. <em>Ho hyios tEs Marias</em> (the son of Mary) is an unusual designation: Jewish naming convention used the father\'s name. A "son of Mary" without mention of the father may be a slight (implying uncertain paternity) or simply the designation appropriate after Joseph\'s death. The brothers and sisters are named as local residents: the family is known.</p>',
    "4": '<p><strong>Kai elegen autois ho IEsous hoti Ouk estin prophEtEs atimos ei mE en tE patridi autou kai en tois syggeneusin autou kai en tE oikia autou</strong> — and Jesus said to them: "a prophet is not without honor except in his hometown and among his relatives and in his own house" — the proverb (attested in similar form in Greco-Roman literature and the Gospel of Thomas 31) establishes a sociological law of familiarity breeding disrespect. The three concentric circles of failure — hometown, relatives (<em>syggeneis</em>), household (<em>oikia</em>) — move from widest to most intimate. The most intimate circle fails most: even his own household is mentioned. This may be the continuation of the family-rejection theme of 3:21.</p>',
    "5": '<p><strong>Kai ouk edynato ekei poiEsai oudemian dynamin</strong> — and he was not able to do any mighty work there — <em>ouk edynato</em> (he was not able) is one of the most theologically challenging statements in the Gospels: it attributes an inability to Jesus. The straightforward reading is that Jesus\'s power to heal was conditioned in some way on the receptivity of those to whom it was directed. Matthew 13:58 softens this to "he did not do many miracles there because of their unbelief" (<em>ouk epoiEsen ekei dynameis pollAs dia ten apistian autOn</em>), changing "was not able" to "did not." Mark preserves the stronger statement without softening. The qualification follows immediately (vv.5b-6a): he did lay hands on a few sick people and heal them. The inability is not total but relates to the major mighty works.</p>',
    "6": '<p><strong>Kai ethaumazen dia ten apistian autOn</strong> — and he marveled because of their unbelief — <em>ethaumazen</em> (was amazed, marveled) — only twice in the Gospels is Jesus amazed: here at the unbelief of Nazareth (v.6) and at the faith of the centurion (Matt 8:10/Luke 7:9). The divine Son\'s genuine astonishment at human <em>apistia</em> (unbelief) is one of the most striking expressions of his genuine humanity in Mark. <strong>Kai periEgen tas kOmas kuklO didaskOn</strong> — and he went around the surrounding villages teaching — the Nazareth rejection drives the mission outward to the villages. Rejection at home becomes the occasion for expansion of the teaching circuit.</p>',
    "7": '<p><strong>Kai proskAleitai tous dOdeka kai Erxato autous apostellein duo duo</strong> — and he called the Twelve and began to send them out two by two — <em>duo duo</em> (two by two — the distributive repetition) is the mission deployment pattern; cf. Luke 10:1 for the 70 sent out two by two. The two-witness principle (Deut 17:6; 19:15) may underlie the practice, as may the practical and safety advantages of paired mission. <strong>Kai edidou autois exousian tOn pneumatOn tOn akathartOn</strong> — and he gave them authority over the unclean spirits — the delegation of Jesus\'s exorcistic authority to the Twelve is the actualization of the founding purpose of 3:15 (<em>echein exousian ekballein ta daimonia</em>).</p>',
    "8": '<p><strong>Kai parEggeilen autois hina mEden airosin eis hodon ei mE rhabdon monon</strong> — and he commanded them that they take nothing for the journey except a staff only — the mission instructions specify what to bring: <em>rhabdon</em> (staff, walking stick) only. The remarkable feature is the contrast with Matthew 10:10 ("nor a staff") — Matthew prohibits the staff; Mark requires it. Various harmonization attempts exist (different stages of the mission, different purposes for the staff); the simplest reading is that the traditions represent variant memories of the instruction. Mark\'s missionaries carry nothing for provision but are allowed the basic walking implement.</p>',
    "9": '<p><strong>Alla hypodEmenous sandalia kai mE endysEsthe dyo chitonas</strong> — "but wearing sandals, and do not put on two tunics" — the sandals (<em>sandalia</em>) are permitted (contrast with the Exodus instruction where sandals are worn for departure readiness, Exod 12:11); the second tunic (<em>chitOn</em> = the inner garment, next to the body) is prohibited — the missionaries travel with what they wear, not with extra clothing. The minimalist travel preparation signals dependence on hospitality rather than self-sufficiency: the missionaries will receive food and lodging from those to whom they minister.</p>',
    "10": '<p><strong>Kai elegen autois, Hopou ean eiselthEte eis oikian, ekei menEte heos an exelthEte ekeithen</strong> — and he said to them: "wherever you enter a house, remain there until you leave from that place" — the single-house rule: missionaries are not to move between households seeking better hospitality. Staying in the first house that receives them models contentment and avoids the social awkwardness of progressive social climbing. The rule also establishes that the missionary\'s purpose is the mission, not the comfort of the host arrangement.</p>',
    "11": '<p><strong>Kai hos an topos mE dExEtai hymas mEde akousOsin hymOn, ekporeuomenoi ekeithen ektinaxate ton choun ton hypokatO tOn podOn hymOn eis martyrion autois</strong> — and whatever place does not receive you and does not hear you, going out from there shake off the dust from under your feet as a testimony against them — <em>ektinaxate ton choun</em> (shake off the dust — the symbolic gesture) enacted by Jews returning from Gentile territory to indicate that they were not carrying Gentile impurity back into the Holy Land. The missionaries perform the gesture toward unresponsive <em>Jewish</em> communities: their rejection is treated as equivalent to Gentile non-reception. <em>Eis martyrion autois</em> (as a testimony against them) — the acted sign witnesses to their judgment.</p>',
    "12": '<p><strong>Kai exelthontes ekEruxan hina metanoOsin</strong> — and going out they proclaimed that people should repent — the Twelve\'s proclamation (<em>kEryssO</em>) carries the same content as John\'s and Jesus\'s: <em>metanoeite</em> (repent, change direction). The mission is an extension of the same proclamation rather than a new message. <em>Hina metanoOsin</em> (so that they might repent — purpose clause) makes repentance the intended outcome of the preaching, not merely its content.</p>',
    "13": '<p><strong>Kai daimonia polla exeballon kai Eleiphon elaiO pollous arrOstous kai etherapeuon</strong> — and they cast out many demons and anointed many sick people with oil and healed them — the anointing with oil (<em>Eleiphon elaiO</em>) is the only Gospel reference to anointing for healing (James 5:14 develops the practice theologically). <em>ElaiOn</em> (oil — olive oil used medicinally and liturgically) is the medium of the healing anointing. The combination of exorcism + anointing-healing is the practical expression of the delegated authority of v.7. The mission\'s results confirm the authority\'s effectiveness.</p>',
    "14": '<p><strong>Kai Ekousen ho basileus HErOdEs, phaneron gar egeneto to onoma autou</strong> — and King Herod heard, for his name had become well-known — <em>ho basileus HErOdEs</em> (King Herod) — Herod Antipas was technically a tetrarch (ruler of a quarter-region: Galilee and Perea), not a king. Mark uses the popular title; Matthew 14:1 and Luke 9:7 both use "tetrarch." The popular title reflects Herod\'s royal ambition and popular perception. <em>Phaneron egeneto to onoma autou</em> (his name had become well-known) — fame as the mechanism of royal intelligence: what the whole region talked about came to Herod\'s attention. The popular speculation (vv.14-15) about Jesus\'s identity reaches the court.</p>',
    "15": '<p><strong>Alloi de elegon hoti Elias estin, alloi de elegon hoti prophEtEs hOs heis tOn prophEtOn</strong> — but others were saying "he is Elijah," and others were saying "a prophet like one of the prophets" — the three popular identifications of Jesus (John the Baptist, Elijah, a prophet) in vv.14-15 parallel and prepare for the three disciples\' answers in 8:28 — and serve as the foil for Peter\'s correct answer in 8:29 (you are the Christ). The Elijah identification reflects the expectation of Mal 4:5 (Elijah before the great day of the LORD). The generic "prophet like one of the prophets" reflects broader prophetic expectation without a specific OT figure.</p>',
    "16": '<p><strong>AkOusas de ho HErOdEs elegen, Hon egO apekephalisa IOannEn, houtos EgerthE</strong> — but Herod hearing said: "John whom I beheaded, this one has been raised" — Herod\'s identification of Jesus with the resurrected John is guilt-driven: he alone makes this specific identification. <em>Egō apekephalisa</em> (I beheaded — the emphatic first person pronoun marks it as personal guilt). <em>Houtos EgerthE</em> (this one was raised — the divine passive <em>egertheō</em> = was raised) is the resurrection verb: Herod uses the same verb that will be used for Jesus\'s own resurrection (16:6). The irony: Herod\'s guilty haunting by John\'s death and resurrection is an unwitting anticipation of the resurrection that will vindicate Jesus.</p>',
    "17": '<p><strong>Autos gar ho HErOdEs aposteilas ekratEsen ton IOannEn kai edEsen auton en phylakE dia HErOdiada tEn gynaika PhilIppou tou adelphou autou, hoti autEn egamEsen</strong> — for Herod himself, having sent, seized John and bound him in prison because of Herodias, the wife of Philip his brother, whom he had married — the political backstory: Herodias was the wife of Herod Philip (possibly Philip the tetrarch, more likely a private half-brother), who divorced his own wife to marry her. The dynastic sexual politics were an open scandal. John\'s public condemnation of the marriage (v.18) was politically dangerous because it challenged the legitimacy of Herod\'s marriage and potentially Herod\'s political alliance with Rome.</p>',
    "18": '<p><strong>Elegen gar ho IOannEs tO HErOdEi hoti Ouk exestin soi echein ten gynaika tou adelphou sou</strong> — for John had been saying to Herod: "it is not lawful for you to have your brother\'s wife" — <em>exestin</em> (it is lawful) — the same halakhic permissibility term used in the Sabbath controversies (2:24; 3:4). John applies the Torah\'s prohibition (Lev 18:16; 20:21 forbid taking a brother\'s wife) to Herod\'s specific case. The imperfect <em>elegen</em> (was saying, kept saying) indicates repeated or continuous denunciation, not a single incident. John\'s public condemnation of royal sexual ethics mirrors Elijah\'s confrontation of Ahab (1 Kgs 18-21) — reinforcing the Elijah-John typology of 1:6.</p>',
    "19": '<p><strong>HE de HErOdias enEichen autO kai Ethelen auton apokteinai kai ouk Edynato</strong> — and Herodias had a grudge against him and wanted to kill him but was not able — <em>enEichen</em> (had a grudge, held within — from <em>enechO</em>, to hold against someone) is the word for nursing a grievance. Herodias wanted John dead but was thwarted — not by moral scruples but by practical constraints (v.20: Herod\'s protection of John). The narrative sets up the birthday banquet as the moment when circumstances finally align for Herodias to accomplish what she had been unable to achieve.</p>',
    "20": '<p><strong>Ho gar HErOdEs ephobeito ton IOannEn eidOs auton andra dikaion kai hagion kai synetErei auton</strong> — for Herod feared John, knowing him to be a righteous and holy man, and was protecting him — the Markan psychology of Herod is surprisingly nuanced: he fears John (<em>ephobeito</em>), recognizes his righteousness and holiness (<em>dikaion kai hagion</em> — the same dual qualification as the divine name, cf. Isa 5:16 LXX), and protects him (<em>synetErei</em> = kept him safe, preserved him). <strong>Kai akoussas autou polla EpoReito kai hEdEOs autou Ekouen</strong> — and having heard him he was greatly perplexed, yet gladly heard him — Herod is simultaneously disturbed (<em>EpoReito</em> = was perplexed, at a loss) and attracted (<em>hEdEOs ... Ekouen</em> = gladly was hearing). The fascination of the guilty with the one who confronts their guilt is a recurring dynamic in Mark\'s court narrative.</p>',
    "21": '<p><strong>Kai genomEnEs hEmEras eukairou hote HErOdEs tois genesiois autou deipnon epoiEsen tois megistAsin autou kai tois chiliarchois kai tois prOtois tEs Galilaias</strong> — and a suitable/opportune day having come, when Herod on his birthday held a banquet for his great men and the commanders of thousands and the leading men of Galilee — <em>hEmEra eukairos</em> (a well-timed day, an opportunity — <em>eukairos</em> from <em>eu</em> + <em>kairos</em>) echoes the demonic <em>kairos</em>-seeking: the right moment for Herodias\'s scheme. The guest list is the military-political hierarchy of the region: <em>megistanes</em> (great men, grandees — the civilian aristocracy), <em>chiliarchoi</em> (commanders of thousands, military tribunes), and the <em>prOtoi tEs Galilaias</em> (leading men of Galilee). The birthday banquet is a public political-social occasion before the entire power structure.</p>',
    "22": '<p><strong>Kai eiselthousEs tEs thygatros autEs tEs HErOdiados kai orchEsamenEs Eresen tO HErOdE kai tois synanakeimenois</strong> — and the daughter of Herodias having entered and having danced, she pleased Herod and those reclining with him — <em>orchEsamenEs</em> (having danced) — the dance of the daughter of Herodias before the assembled military-political leadership of Galilee is the mechanism of Herodias\'s scheme. Her identity is clarified as <em>hE thygatEr autEs tEs HErOdiados</em> (the daughter of Herodias herself) — her daughter, not Herod\'s. The king\'s pleasure in the performance creates the rash public oath that Herodias will exploit.</p>',
    "23": '<p><strong>Kai OmOsen autE polla, hoti Ho ean me aitEsEs dOsO soi heos hEmisous tEs basileias mou</strong> — and he swore to her at length: "whatever you ask me I will give you, up to half my kingdom" — the exaggerated royal oath (<em>heOs hEmisous tEs basileias mou</em> = up to half my kingdom) is a literary formula for extreme generosity, attested in Esther 5:3,6; 7:2 (the Ahasuerus/Esther parallel may be intentional — Herodias uses the banquet the way Esther did, but for inverse purposes). The oath before witnesses (<em>tois synanakeimenois</em> = those reclining with him) creates the social trap: Herod must either honor the oath or suffer public humiliation.</p>',
    "24": '<p><strong>Kai exelthousa eipen tE mEtri autEs, Ti aitEsOmai? hE de eipen, Ten kephalEn IOannou tou baptizontos</strong> — and going out she said to her mother: "what shall I ask?" and she said: "the head of John the baptizer" — the daughter\'s question to her mother reveals that the dance was orchestrated: Herodias had been waiting for exactly this opportunity. The request for the head (<em>kephalEn</em>) is the specific form of the execution proof, and the phrase "of John the baptizer" identifies the target precisely. Herodias\'s strategy succeeds because Herod has made a public oath before his court: refusal would mean humiliation more politically damaging than the execution.</p>',
    "25": '<p><strong>Kai eiselthousa euthys meta spoudEs pros ton basilea EtEsato legousA, ThelO hina exautEs dOs moi epi pinaki ten kephalEn IOannou tou baptistou</strong> — and entering immediately with haste to the king she asked saying: "I want you to give me right now, on a dish, the head of John the Baptist" — <em>euthys meta spoudEs</em> (immediately with haste) — the daughter\'s urgency prevents Herod from reconsidering; the demand is immediate. <em>Exautēs</em> (right now, at once — from <em>ex autēs tēs hōras</em>, from this very hour) adds temporal pressure. <em>Epi pinaki</em> (on a dish/platter) — the specification of the serving dish for the head transforms the execution into a banquet spectacle.</p>',
    "26": '<p><strong>Kai perIlypos genomenos ho basileus dia tous horkous kai tous anakeimenous ouk EthelEsen athetEsai autEn</strong> — and the king, being deeply grieved, because of his oaths and those reclining, did not want to refuse her — <em>perilOpos</em> (deeply grieved — <em>peri</em> + <em>lypos</em>, sorrowful all around) — Herod is genuinely distressed by the request. His refusal to refuse is not moral indifference but the social entrapment of the public oath: <em>dia tous horkous kai tous anakeimenous</em> (because of the oaths and those reclining). The witnesses to the oath ensure that Herod cannot retreat without public humiliation. The political cost of dishonoring a public oath before the military commanders of Galilee is higher than the moral cost of killing a righteous man.</p>',
    "27": '<p><strong>Kai euthys aposteilas ho basileus spekoulatOra epetaxen enechthEnai ten kephalEn autou</strong> — and immediately the king, having sent a soldier-executioner, commanded his head to be brought — <em>euthys</em> (immediately) — Herod executes the command at once to prevent second thoughts. <em>Spekoulat Or</em> (speculator — a Latin loanword: a member of the royal bodyguard who served as executioner, spy, and courier) is a Latin military term preserved in Mark\'s Greek. It is the only occurrence of the word in the NT and reflects Mark\'s Latin-influenced vocabulary (consistent with a Roman provenance for the Gospel).</p>',
    "28": '<p><strong>Kai apelthOn apekephalisen auton en tE phylakE kai Enegken tEn kephalEn autou epi pinaki kai edOken autEn tO korasiO, kai to korasion edOken autEn tE mEtri autEs</strong> — and going he beheaded him in the prison and brought his head on a dish and gave it to the girl, and the girl gave it to her mother — the four steps of the delivery are narrated without commentary: beheading in prison, bringing the head on the dish, giving it to the girl, the girl giving it to her mother. The stark narration without editorial judgment is the Markan style: the reader supplies the moral weight. The head that proclaimed repentance in the wilderness becomes the centerpiece of a court banquet.</p>',
    "29": '<p><strong>Kai akousantes hoi mathEtai autou Elthan kai Eran to ptOma autou kai ethEkan auto en mnEmeio</strong> — and having heard, his disciples came and took his body and laid it in a tomb — the burial of John by his disciples (<em>hoi mathEtai autou</em>) prepares for the burial of Jesus by Joseph (15:46) and parallels the women\'s care for the body. The tomb (<em>mnEmeion</em>) is the word used throughout the passion narrative for Jesus\'s tomb. The disciples of the forerunner bury the forerunner; the disciples of Jesus will fail to appear at his burial (women alone attend).</p>',
    "30": '<p><strong>Kai synagontai hoi apostoloi pros ton IEsoun kai apEggeilan autO panta hosa epoiEsan kai hosa edidaskan</strong> — and the apostles gathered to Jesus and reported to him all they had done and all they had taught — <em>hoi apostoloi</em> (the apostles) — the only occurrence of this title in Mark (it appears once elsewhere in some manuscripts). The report covers both activity (<em>epoiEsan</em> = what they did) and teaching (<em>edidaskan</em> = what they taught). The separation of doing from teaching reflects the dual commission of 6:7-13: exorcism/healing (doing) and preaching repentance (teaching). The return-and-report to Jesus is the completion of the mission-sending pattern begun in v.7.</p>',
    "31": '<p><strong>Kai legei autois, Deute hymeis autoi kat\' idian eis erEmon topon kai anapauesthe oligon</strong> — and he said to them: "come away by yourselves privately to a lonely place and rest a little" — <em>deute</em> (come! — the plural imperative of invitation, also used in 1:17 "come, follow me") + <em>kat\' idian</em> (privately, by themselves) + <em>erEmon topon</em> (lonely/desert place — the wilderness as the place of divine encounter and necessary withdrawal). <em>AnapauestheOligon</em> (rest a little — <em>anApauO</em> = to give rest, refresh) is the pastoral provision for the exhausted missionaries: the same care Jesus showed in 1:35 (withdrawing for prayer) is now extended to the Twelve.</p>',
    "32": '<p><strong>Kai apElthon en tO ploiO eis erEmon topon kat\' idian</strong> — and they went away in the boat to a lonely place privately — the withdrawal by boat is the same movement as 4:35-36: escaping the crowd by water. The private retreat never arrives: v.33 shows the crowd anticipating them and arriving first. The intended rest becomes the occasion for the feeding of the 5,000. The disciples\' need for rest (v.31) is not met in this episode; it will be deferred again and again by the crowds\' need.</p>',
    "33": '<p><strong>Kai eidon autous hypagontas kai epegnOsan polloi, kai pezE apo pasOn tOn poleOn synedramon ekei kai proElthon autous</strong> — and many saw them going and recognized them, and on foot from all the cities they ran together there and got ahead of them — the crowd\'s pursuit on foot outpaces the boat: <em>proElthon autous</em> (got ahead of them) — the crowd arrives at the intended landing point before the boat. The determination of the crowd to find Jesus (running from all the cities) is the reverse image of the disciples\' need for rest: the needy crowd and the exhausted disciples converge on the same lonely place.</p>',
    "35": '<p><strong>Kai EdE hOras pollEs genomEnEs proselthontes autO hoi mathEtai autou elegon hoti ErEmos estin ho topos kai EdE hOra pollE</strong> — and the hour already being late, his disciples came to him and said: "this is a remote place and the hour is already late" — the practical problem is stated plainly: remote location + late hour + large crowd = a feeding emergency. The disciples\' solution in v.36 (send them to buy food) is sensible but misses the opportunity that Jesus will create. The Markan inclusion of this practical logistical framing (<em>hOra pollE</em> = the hour is late; <em>ErEmos estin ho topos</em> = remote place) grounds the miraculous feeding in physical necessity.</p>',
    "36": '<p><strong>Apoluson autous, hina apelthontes eis tous kyklO agrous kai kOmas agorAsOsin heautois ti phAgOsin</strong> — send them away so that going to the surrounding farms and villages they may buy themselves something to eat — the disciples\' solution is the rational management of the problem: disperse the crowd to the nearest food sources. <em>AgorasOsin</em> (they may buy) — commercial transaction as the obvious solution to feeding 5,000 people. The disciples have not yet imagined the alternative that Jesus will propose. Their answer to Jesus\'s "give them something to eat" (v.37) will be the economic calculation that reveals the inadequacy of commercial thinking for kingdom provision.</p>',
    "37": '<p><strong>HO de apokritheis eipen autois, Dote autois hymeis phagein</strong> — but answering he said to them: "you give them something to eat" — the command is emphatic: <em>hymeis</em> (you — plural, the disciples themselves) are the agents. The command is impossible by the disciples\' resources (<em>apelthontes agorAsOmen denarion diakosiOn artous kai dOsomen autois phagein?</em> = are we to go and buy loaves worth 200 denarii and give them to eat?). 200 denarii is approximately 200 days\' wages for an agricultural laborer — roughly eight months\' income. The economic calculation frames the miracle in terms of the enormous gap between what is available and what is needed.</p>',
    "38": '<p><strong>Ho de legei autois, Posous artous echete? hypagete idete</strong> — and he said to them: "how many loaves do you have? go and see" — the command to investigate the available resources before acting is the Christological method: acknowledge what is present, however inadequate, and let Jesus work with it. The answer: five loaves and two fish. Five and two are not fractions of the 200 denarii calculation; they are below any threshold of adequacy for 5,000 men.</p>',
    "39": '<p><strong>Kai epetaxen autois anaklithenai pantas symposia symposia epi tO chlorO chortO</strong> — and he commanded them to have everyone recline, party by party, on the green grass — <em>symposia symposia</em> (party by party — the Aramaic distributive repetition for group arrangement) and <em>chlorO chortO</em> (green grass — <em>chloros</em> = green, fresh; <em>chortos</em> = grass/vegetation) specifies both organization and season: the green grass places this in early spring, consistent with the Passover season (John 6:4 explicitly mentions the nearness of Passover). The organized seating in groups anticipates the orderly distribution.</p>',
    "40": '<p><strong>Kai anepesan prasiai prasiai, hekaton kai pentEkonta</strong> — and they reclined, garden-plot by garden-plot, by hundreds and by fifties — <em>prasiai prasiai</em> (garden-plot by garden-plot — <em>prasia</em> = a garden bed/plot) is a second distributive image: the organized groups look like the rows of a cultivated garden seen from above. The specific numbers (hundreds and fifties) echo the Exodus organizational structure (Exod 18:21,25 — Jethro\'s advice to Moses to organize Israel in groups of thousands, hundreds, fifties, tens). The feeding in the wilderness before organized Israel echoes the manna-feeding.</p>',
    "41": '<p><strong>Kai labOn tous pente artous kai tous dyo ichthyas anablepAs eis ton ouranon eulogEsen kai kateklasen tous artous kai edidou tois mathEtais autou hina paratithOsin autois</strong> — and taking the five loaves and the two fish, looking up to heaven, he blessed and broke the loaves and was giving to his disciples to set before them — the fourfold action: <em>labOn</em> (took), <em>eulogEsen</em> (blessed/gave thanks), <em>kateklasen</em> (broke), <em>edidou</em> (was giving) — this is the eucharistic formula (cf. 14:22 at the Last Supper; 1 Cor 11:23-24). The parallel language is deliberate: the feeding of the 5,000 anticipates and interprets the Last Supper, and both anticipate the resurrection meals. <em>AnablepAs eis ton ouranon</em> (looking up to heaven) is the gesture of prayer before the blessing.</p>',
    "42": '<p><strong>Kai ephagon pantes kai echortAsthEsan</strong> — and all ate and were satisfied — <em>pantes</em> (all) + <em>echortAsthEsan</em> (were satisfied, filled to contentment — from <em>chortazO</em>, to feed to satiation, to satisfy fully; the same word used in 8:8 for the feeding of the 4,000 and in the Beatitudes, Matt 5:6). The satisfaction of all 5,000 men (plus women and children, Matt 14:21) is the miracle\'s outcome: not merely enough but satisfying. <em>ChortazO</em> is also the LXX verb for the divine provision in the wilderness (Ps 78:29 LXX: <em>kai echortAsthEsan sphodra</em> = and they were fully satisfied) — the Exodus-feeding parallel is operative.</p>',
    "43": '<p><strong>Kai Eran klasmaton dOdeka kophinous plErEis kai apo tOn ichthyOn</strong> — and they picked up twelve basketfuls of broken pieces and of the fish — <em>dOdeka kophinous</em> (twelve baskets — <em>kophinos</em> = the wicker basket carried by Jews for their own food in the marketplace, to avoid eating non-kosher food). The twelve baskets correspond to the twelve disciples (who distributed) and the twelve tribes of Israel (whom the feeding feeds symbolically). The excess provision is greater than the original: twelve full baskets from five loaves and two fish.</p>',
    "44": '<p><strong>Kai Esan hoi phagontes tous artous pentakischilioi andres</strong> — and those who ate the loaves were five thousand men — <em>pentakischilioi andres</em> (five thousand men — <em>andres</em> = adult males specifically). The counting of men only follows the convention used in census-taking (Exod 12:37; Num 1:46); women and children would increase the total. The number five thousand is the scale marker: the feeding of 5,000+ with five loaves and two fish with twelve baskets of leftovers is the Christological demonstration of provision on the scale of the Exodus manna.</p>',
    "45": '<p><strong>Kai euthys Enagkasen tous mathEtas autou embEnai eis to ploion kai proagein eis to peran pros BEthsaIdan</strong> — and immediately he compelled his disciples to get into the boat and go ahead to the other side toward Bethsaida — <em>euthys Enagkasen</em> (immediately he compelled — <em>anagkazO</em> = to compel, force, constrain) is a strong word: Jesus forces the disciples into the boat. John 6:15 explains why: the crowd was about to make Jesus king by force, and Jesus removes his disciples from that political pressure. The boat departure is not relaxed but urgent; the disciples are removed from the scene while Jesus dismisses the crowd.</p>',
    "46": '<p><strong>Kai apotaxamenos autois apElthen eis to oros proseuxasthai</strong> — and having dismissed/taken leave of them, he went off to the mountain to pray — the pattern of withdrawal for prayer (1:35) is repeated after the feeding. The mountain setting is Sinai-echoing: Moses encountered God on the mountain; Elijah encountered God on the mountain (1 Kgs 19:8); Jesus prays on the mountain and will walk on the water. The prayer in solitude precedes the theophanic walking-on-water: the mountain prayer connects to the divine encounter that the walking on the sea will demonstrate.</p>',
    "47": '<p><strong>Kai opsias genomEnEs En to ploion en mesO tEs thalassEs, kai autos monos epi tEs gEs</strong> — and evening having come, the boat was in the middle of the sea and he was alone on the land — the spatial staging of the scene: Jesus on the mountain praying, the disciples in the middle of the lake, a distance between them that will be crossed by walking on water. <em>Monos</em> (alone) — Jesus alone on the land is the condition that will end when he goes to them on the sea. The disciples are not visible from the shore but Jesus sees them (v.48: <em>kai eidon autous</em>).</p>',
    "48": '<p><strong>Kai idOn autous basanizomenous en tO elaunein</strong> — and seeing them straining at the oars — <em>basanizomenous</em> (being tormented, tortured — the word <em>basanizO</em> is used for demonic torment in 5:7) applied to the physical strain of rowing against a headwind: the disciples are being "tormented" by the wind and the effort of rowing. <strong>Peri tetartEn phylakEn tEs nyktos erchetai pros autous peripatOn epi tEs thalassEs</strong> — about the fourth watch of the night he came to them walking on the sea — the fourth watch (3-6 AM) is the final watch before dawn. <strong>Kai Ethelen parelthein autous</strong> — and he wanted to pass by them — <em>parelthein</em> (to pass by) is the theophanic vocabulary of Exod 33:19,22; 34:6 (the LORD passing by Moses on Sinai) and 1 Kgs 19:11 (the LORD passing by Elijah on Horeb). The "passing by" is not indifference but theophanic self-disclosure.</p>',
    "49": '<p><strong>Hoi de idontes auton epi tEs thalassEs peripatounta edoxan hoti phantasma estin kai anekraxan</strong> — but seeing him walking on the sea they thought he was a phantom and cried out — <em>phantasma</em> (phantom, ghost — from <em>phantasma</em>, an apparition, something that appears but has no substance) is the disciples\' interpretation of what they see: an insubstantial vision rather than the embodied Jesus. The cry (<em>anekraxan</em>) is the cry of fear, the same response as the demonic cry (<em>anekrazen</em>) in 1:23. Walking on water is outside the category of the humanly possible; the disciples default to the supernatural explanation of a ghost.</p>',
    "50": '<p><strong>Pantes gar auton eidon kai etarachthEsan. Ho de euthys elalEsen met\' autOn kai legei autois, TharsEite, egO eimi, mE phobeIsthe</strong> — for all saw him and were troubled. But immediately he spoke with them and said to them: "take courage, I AM, do not be afraid" — <em>egO eimi</em> (I am — or, the absolute form: I AM) is the divine name of Exod 3:14 and Deut 32:39 (LXX: <em>egO eimi</em>). The theophanic formula "I AM" combined with "do not be afraid" (<em>mE phobeIsthe</em>) is exactly the pattern of divine self-revelation in the OT: God appears, says "I AM," commands the cessation of fear (cf. Isa 41:4,10; 43:10-13; 51:12). Jesus\'s self-identification in the storm is the divine name spoken by the one walking on the water.</p>',
    "51": '<p><strong>Kai anebE pros autous eis to ploion kai ekopasen ho anemos kai lian ek perissou en heautois existanto</strong> — and he went up to them into the boat and the wind ceased and they were utterly beside themselves — the wind ceases as in the storm-stilling of 4:39; the Christological connection is explicit: the same authority over wind and sea that operated in 4:39 now operates again. <em>Lian ek perissou ... existanto</em> (utterly beyond measure... were beside themselves) — the superlatives pile up for maximal astonishment. But v.52 will diagnose this amazement as inadequate: they were amazed because they had not understood.</p>',
    "52": '<p><strong>Ou gar synEkan epi tois artois, all\' En autOn hE kardia pePOrOmenE</strong> — for they had not understood about the loaves, but their heart was hardened — <em>pePOrOmenE</em> (hardened — perfect passive participle of <em>pOrOO</em>, to harden, petrify, callus) is the same word used in 3:5 for the Pharisees\' heart-hardness. The extraordinary diagnosis: the disciples\' hearts are hardened. The feeding of the 5,000 should have revealed Jesus\'s identity; their failure to understand (<em>ou synEkan</em> = had not understood) is now attributed to heart-hardness rather than mere intellectual incomprehension. The disciples\' blindness is the same kind of blindness as the opponents\'. This is the harshest Christological diagnosis of the disciples in Mark.</p>',
    "53": '<p><strong>Kai diaperasantes epi ten gen Elthan eis Gennesaret kai prosoOrmisthEsan</strong> — and having crossed over to the land they came to Gennesaret and anchored — <em>Gennesaret</em> (also <em>Ginosar</em>) is the fertile plain on the northwest shore of the lake, south of Capernaum; the lake is called "the Lake of Gennesaret" in Luke 5:1. The anchoring (<em>prosOrmisthEsan</em> = they were moored, brought to anchorage) is the nautical technical term for tying up a boat. The transition from the theophanic sea-crossing to the ordinary lakeshore landing is characteristically abrupt in Mark.</p>',
    "54": '<p><strong>Kai exelthonton autOn ek tou ploiou euthys epignontes auton</strong> — and when they got out of the boat, immediately the people recognized him — <em>euthys epignontes auton</em> (immediately recognizing him) — the recognition is public and immediate, consistent with the spread of Jesus\'s fame through the region (1:28; 3:7-8). The Gennesaret population knows who Jesus is and knows what he can do; they mobilize immediately (v.55) to bring the sick to him.</p>',
    "55": '<p><strong>PeriedrAmon holen ten chOran ekeinEn kai Erxanto epi tois krabattois tous kakOs echontas peripherein hopou Ekouon hoti estin</strong> — they ran throughout that whole region and began to carry around on mats those who were sick to wherever they heard he was — the response-pattern of 1:32-34 and 3:7-12 is repeated in summary form: <em>peripherein</em> (carrying around, transporting) the sick on <em>krabattos</em> mats (the low-status sleeping mat of 2:4,9,11,12) to wherever Jesus is. The running (<em>periEdAmon</em> = ran around) suggests urgency and energy. The whole region mobilizes to find Jesus.</p>',
    "56": '<p><strong>Kai hopou an eisEporeueto eis kOmas E eis poleis E eis agrous, en tais agorais etithEsan tous asthenountas kai parEkaloun auton hina kan tou kraspEdou tou himatiou autou hapsOntai</strong> — and wherever he went into villages or into cities or into farms, they placed the sick in the marketplaces and were begging him that they might touch even the fringe of his garment — <em>kraspEdon tou himatiou</em> (fringe/edge of the garment) — in Matthew 23:5 the <em>kraspEda</em> are the tassels (<em>tsitzit</em>) commanded in Num 15:38-40 as reminders of the commandments. The fringe-touch echoes 5:27-28 (the hemorrhaging woman\'s garment-touch). The summary of healing concludes the Galilee section: <em>hosos an hEpsanto autou esOzonto</em> — as many as touched him were healed/saved.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'mark')
    merge_comm(existing, MARK)
    save_comm('mkt-original', 'mark', existing)
    print('Mark 5-6 mkt-original written.')

if __name__ == '__main__':
    main()
